<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Detalle del pago</title><link rel="stylesheet" href="<?=BASE_URL?>/public/css/estilos.css"><link rel="stylesheet" href="<?=BASE_URL?>/public/css/admin.css"></head><body class="admin-page"><?php require __DIR__.'/../partials/navbar.php';?><div class="admin-layout"><?php require __DIR__.'/../partials/sidebar.php';?><main class="admin-main"><?php require __DIR__.'/../../partials/flash.php';?><section class="admin-payment-detail"><h1>Detalle del pago</h1><dl><?php foreach(['Folio'=>$pago['folio'],'Alumno'=>$pago['alumno'],'Matrícula'=>$pago['matricula'],'Correo'=>$pago['correo'],'Periodo'=>$periodoTexto,'Método'=>$pago['metodo_pago'],'Importe'=>'$'.number_format((float)$pago['total_pagado'],2),'Fecha de pago'=>$pago['fecha_pago'],'Origen'=>$pago['origen'],'Estado'=>$pago['estado_validacion'],'Registrado por'=>$pago['registrado_por_nombre']??'No aplica','Validado por'=>$pago['validado_por_nombre']??'No aplica','Fecha de validación'=>$pago['fecha_validacion']??'Pendiente','Observaciones'=>$pago['observaciones']??'Sin observaciones'] as $l=>$v):?><div><dt><?=$l?></dt><dd><?=htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8')?></dd></div><?php endforeach;?></dl><?php if($pago['estado_validacion']==='Pendiente'):?><div class="admin-payment-actions"><form method="post" action="<?=BASE_URL?>/index.php?ruta=admin-pago-validar" data-confirm="¿Deseas validar este pago? El adeudo será marcado como Pagado."><input type="hidden" name="csrf_token" value="<?=htmlspecialchars($csrfToken,ENT_QUOTES,'UTF-8')?>"><input type="hidden" name="id_pago" value="<?=(int)$pago['id_pago']?>"><button>Validar</button></form><form class="admin-payment-reject-form" method="post" action="<?=BASE_URL?>/index.php?ruta=admin-pago-rechazar" data-confirm="¿Deseas rechazar este pago? El adeudo permanecerá Pendiente."><input type="hidden" name="csrf_token" value="<?=htmlspecialchars($csrfToken,ENT_QUOTES,'UTF-8')?>"><input type="hidden" name="id_pago" value="<?=(int)$pago['id_pago']?>"><input name="motivo" minlength="5" maxlength="255" required placeholder="Motivo del rechazo"><button>Rechazar</button></form></div><?php endif;?><a class="admin-debt-back-button" href="<?=BASE_URL?>/index.php?ruta=admin-pagos">Volver a Gestión de Pagos</a></section></main></div><script src="<?=BASE_URL?>/public/js/admin.js"></script></body></html>
